const payload = items[0] && items[0].json && typeof items[0].json === 'object'
  ? items[0].json
  : {};
const context = payload._promptBuilderContext;
if (!context || typeof context !== 'object' || Object.keys(context).length === 0) {
  return items;
}
return items.map((item) => ({
  json: Object.assign({}, item.json || {}, context),
}));

const TEMPLATE_VERSION = 'telegram-v2.2';

const DEFAULT_CHAT_ID = '730354404';

const isObject = (value) => value !== null && typeof value === 'object' && !Array.isArray(value);

const parseContent = (input) => {
  if (typeof input !== 'string') {
    return input;
  }
  try {
    return JSON.parse(input);
  } catch {
    return null;
  }
};

const payloads = items
  .map((item) => (item && item.json ? item.json : {}))
  .filter((payload) => payload && Object.keys(payload).length > 0);

const getNodeItemsSafe = (nodeName) => {
  try {
    const nodeItems = $items(nodeName);
    return Array.isArray(nodeItems) ? nodeItems : [];
  } catch {
    return [];
  }
};

const fallbackNodeNames = [
  'Build Run Event (success)',
  'Validate WeeklyPlan (attempt 0)',
];

const fallbackNodeCounts = {};
const fallbackPayloads = [];
for (const nodeName of fallbackNodeNames) {
  const nodeItems = getNodeItemsSafe(nodeName);
  fallbackNodeCounts[nodeName] = nodeItems.length;
  for (const nodeItem of nodeItems) {
    const payload = nodeItem && nodeItem.json ? nodeItem.json : {};
    if (payload && Object.keys(payload).length > 0) {
      fallbackPayloads.push(payload);
    }
  }
}

const allPayloads = [...payloads, ...fallbackPayloads];

const parsePlanCandidate = (payload) => {
  const raw = Array.isArray(payload.choices)
    ? payload.choices[0] && payload.choices[0].message
      ? payload.choices[0].message.content
      : null
    : payload;
  const parsed = parseContent(raw);
  return isObject(parsed) ? parsed : null;
};

const parsedCandidates = allPayloads
  .map((payload) => parsePlanCandidate(payload))
  .filter((payload) => payload !== null);

const content = parsedCandidates.find((payload) => isObject(payload.activityPlan)) || null;
if (!content) {
  const inboundKeys = payloads
    .slice(0, 3)
    .map((payload) => Object.keys(payload).slice(0, 8));
  throw new Error(
    `Missing or invalid activityPlan in response. inbound_payloads=${payloads.length}; fallback_counts=${JSON.stringify(fallbackNodeCounts)}; inbound_keys=${JSON.stringify(inboundKeys)}`,
  );
}

const supplementalPayload = {};

const plan = content.activityPlan;
const nextWeek = isObject(plan.nextWeek) ? plan.nextWeek : {};
const days = Array.isArray(plan.days) ? plan.days : [];
const justifications = Array.isArray(content.justification) ? content.justification : [];

const getVar = (key) => {
  if (typeof $vars !== 'undefined' && $vars[key] != null) {
    return String($vars[key]);
  }
  if (typeof process !== 'undefined' && process.env && process.env[key] != null) {
    return String(process.env[key]);
  }
  return '';
};

const isTruthy = (value) => ['1', 'true', 'yes', 'on'].includes(String(value).toLowerCase());

const previewEnabled = isTruthy(getVar('RC_TELEGRAM_PREVIEW_MODE'));
const previewChatRaw = getVar('RC_TELEGRAM_PREVIEW_CHAT_ID').trim();
if (previewEnabled && !previewChatRaw) {
  throw new Error('RC_TELEGRAM_PREVIEW_CHAT_ID is required when RC_TELEGRAM_PREVIEW_MODE is enabled.');
}
const targetChatId = previewEnabled ? previewChatRaw : DEFAULT_CHAT_ID;

const runContextItems = $items('Prompt Builder');
const runContext = runContextItems.length ? runContextItems[0].json : {};
const metrics = isObject(runContext.metrics) ? runContext.metrics : {};
const history = Array.isArray(runContext.history) ? runContext.history : [];

const heartRate = isObject(runContext.heartRate) ? runContext.heartRate : {};
const hrSyncLog = isObject(heartRate.hrSyncLog) ? heartRate.hrSyncLog : {};
const zonesUpdated = Boolean(heartRate.zonesUpdated);
const toHrString = (value) => (value === null || value === undefined || value === '' ? '-' : String(Math.round(Number(value))));
const zoneUpdateNotice = zonesUpdated
  ? (typeof heartRate.zoneUpdateNotice === 'string' && heartRate.zoneUpdateNotice.trim()
      ? heartRate.zoneUpdateNotice.trim()
      : `🛠️ Zonas actualizadas: Max ${toHrString(hrSyncLog.hrMax_old)}→${toHrString(hrSyncLog.hrMax_new)} · Reposo ${toHrString(hrSyncLog.hrRest_old)}→${toHrString(hrSyncLog.hrRest_new)} · Umbral ${toHrString(hrSyncLog.lthr_old)}→${toHrString(hrSyncLog.lthr_new)}`)
  : null;


const valueOr = (value, fallback = '--') => {
  if (value === null || value === undefined) return fallback;
  const text = String(value).trim();
  return text || fallback;
};

const esc = (value) => String(value)
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

const num = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
};

const mean = (values) => {
  const valid = values.map(num).filter((value) => value !== null);
  if (!valid.length) return null;
  return valid.reduce((sum, value) => sum + value, 0) / valid.length;
};

const fmt = (value, suffix = '') => (value === null ? '--' : `${value.toFixed(1)}${suffix}`);
const pct = (value) => (value === null ? '--' : `${(value * 100).toFixed(0)}%`);

const intOrZero = (value) => {
  const parsed = Number.parseInt(value, 10);
  return Number.isFinite(parsed) ? parsed : 0;
};

const normalizeDay = (value) => String(value || '')
  .toLowerCase()
  .replace(/[áàä]/g, 'a')
  .replace(/[éèë]/g, 'e')
  .replace(/[íìï]/g, 'i')
  .replace(/[óòö]/g, 'o')
  .replace(/[úùü]/g, 'u')
  .replace(/ñ/g, 'n');

const dayOrder = {
  lunes: 0,
  monday: 0,
  martes: 1,
  tuesday: 1,
  miercoles: 2,
  wednesday: 2,
  jueves: 3,
  thursday: 3,
  viernes: 4,
  friday: 4,
  sabado: 5,
  saturday: 5,
  domingo: 6,
  sunday: 6,
};

const sortedDays = [...days].sort((a, b) => {
  const aOrder = dayOrder[normalizeDay(a.day)];
  const bOrder = dayOrder[normalizeDay(b.day)];
  const safeA = aOrder === undefined ? 99 : aOrder;
  const safeB = bOrder === undefined ? 99 : bOrder;
  if (safeA !== safeB) return safeA - safeB;
  return String(a.date || '').localeCompare(String(b.date || ''));
});

const ctlNow = num(metrics.ctlActs);
const atlNow = num(metrics.atlActs);
const rampNow = num(metrics.rampActs);
const trimpNow = num(metrics.totalTrimp);
const restNow = num(metrics.restHR);
const hrvNow = num(metrics.hrvWel);
const sleepNow = num(metrics.sleepWel);
const stepsNow = num(metrics.steps);

const lastWeekSummaryLines = [];
if (ctlNow !== null || atlNow !== null || rampNow !== null) {
  lastWeekSummaryLines.push(`Carga (CTL/ATL/Ramp): ${fmt(ctlNow)} / ${fmt(atlNow)} / ${fmt(rampNow)}`);
}
if (trimpNow !== null) {
  lastWeekSummaryLines.push(`TRIMP semanal: ${fmt(trimpNow)}`);
}
if (restNow !== null || hrvNow !== null || sleepNow !== null) {
  lastWeekSummaryLines.push(`Recuperación: FC reposo ${fmt(restNow)} bpm, HRV ${fmt(hrvNow)}, Sueño ${fmt(sleepNow)}`);
}
if (stepsNow !== null) {
  lastWeekSummaryLines.push(`Pasos medios/día: ${fmt(stepsNow)}`);
}
const hasLastWeekSummaryData = lastWeekSummaryLines.length > 0;
if (!hasLastWeekSummaryData) {
  lastWeekSummaryLines.push('Sin métricas recientes.');
}


const weekStart = valueOr(nextWeek.weekStart);
const weekEnd = valueOr(nextWeek.weekEnd);
const phase = valueOr(nextWeek.phase);
const objective = valueOr(nextWeek.objective);

const thisWeekGoalLines = [
  `Semana: ${weekStart} -> ${weekEnd}`,
  `Fase: ${phase}`,
  `Objetivo: ${objective}`,
];
if (justifications.length) {
  const rationale = justifications
    .slice(0, 3)
    .map((item) => valueOr(item))
    .join(' | ');
  thisWeekGoalLines.push(`Justificación breve: ${rationale}`);
}
const hasThisWeekGoalData = [nextWeek.weekStart, nextWeek.weekEnd, nextWeek.phase, nextWeek.objective].some(Boolean);

const dailyPlanLines = sortedDays.map((day) => {
  const dayName = valueOr(day.day, 'Día');
  const date = valueOr(day.date);
  const activity = valueOr(day.activity);
  const distanceTime = valueOr(day.distance_time);
  const intensity = valueOr(day.intensity);
  const goal = valueOr(day.goal);
  const note = day.note ? ` | Nota: ${valueOr(day.note, '')}` : '';
  return `${dayName} (${date}) · ${activity} | ${distanceTime} | ${intensity} | ${goal}${note}`;
});
if (!dailyPlanLines.length) {
  dailyPlanLines.push('Sin detalle diario disponible.');
}
const hasCompleteDailyPlan = sortedDays.length === 7;

const combinedText = (day) => `${valueOr(day.activity, '')} ${valueOr(day.intensity, '')} ${valueOr(day.goal, '')} ${valueOr(day.note, '')}`.toLowerCase();
const hardPattern = /(\bz4\b|\bz5\b|vo2|tempo|threshold|umbral|interval)/;
const longPattern = /(\blong\b|tirada|larga)/;

const keySessionDay = sortedDays.find((day) => hardPattern.test(combinedText(day)))
  || sortedDays.find((day) => longPattern.test(combinedText(day)))
  || sortedDays[0]
  || null;

const keySessionLines = [];
if (keySessionDay) {
  keySessionLines.push(
    `${valueOr(keySessionDay.day, 'Día')} (${valueOr(keySessionDay.date)}) · ${valueOr(keySessionDay.activity)} | ${valueOr(keySessionDay.distance_time)} | ${valueOr(keySessionDay.intensity)} | ${valueOr(keySessionDay.goal)}`,
  );
  if (keySessionDay.note) {
    keySessionLines.push(`Nota: ${valueOr(keySessionDay.note, '')}`);
  }
} else {
  keySessionLines.push('Sin sesión clave identificada.');
}
const hasKeySessionData = Boolean(keySessionDay);

const baselineHrv = mean(history.map((entry) => entry.hrvMean));
const baselineRest = mean(history.map((entry) => entry.restHrMean));
const baselineRamp = mean(history.map((entry) => entry.rampRateMean));

const rationaleCandidates = [];
const addRationale = (text, metricKeys) => {
  rationaleCandidates.push({ text, metricKeys });
};

if (ctlNow !== null && atlNow !== null && rampNow !== null) {
  addRationale(
    `Balance de carga: CTL ${fmt(ctlNow)}, ATL ${fmt(atlNow)}, ramp ${fmt(rampNow)}.`,
    ['ctlActs', 'atlActs', 'rampActs'],
  );
}
if (trimpNow !== null) {
  addRationale(
    `Volumen semanal: TRIMP total ${fmt(trimpNow)}.`,
    ['totalTrimp'],
  );
}
if (restNow !== null && hrvNow !== null && sleepNow !== null) {
  addRationale(
    `Perfil de recuperación: FC reposo ${fmt(restNow)} bpm, HRV ${fmt(hrvNow)}, Sueño ${fmt(sleepNow)}.`,
    ['restHR', 'hrvWel', 'sleepWel'],
  );
}
if (hrvNow !== null && baselineHrv !== null && restNow !== null && baselineRest !== null) {
  addRationale(
    `Tendencia vs base: HRV ${fmt(hrvNow)} vs ${fmt(baselineHrv)}, FC reposo ${fmt(restNow)} vs ${fmt(baselineRest)} bpm.`,
    ['hrvWel', 'histHrv', 'restHR', 'histRestHR'],
  );
}
if (stepsNow !== null) {
  addRationale(
    `Soporte de actividad: pasos medios ${fmt(stepsNow)}.`,
    ['steps'],
  );
}
if (rampNow !== null && baselineRamp !== null) {
  addRationale(
    `Gestión de ramp: actual ${fmt(rampNow)} vs base ${fmt(baselineRamp)}.`,
    ['rampActs', 'histRamp'],
  );
}

let whyPlanHallucinationFailures = 0;
const whyThisPlan = [];
const whyMetricGroups = [];
for (const candidate of rationaleCandidates) {
  const invalid = candidate.metricKeys.some((key) => key == null || key === '');
  if (invalid) {
    whyPlanHallucinationFailures += 1;
    continue;
  }
  whyThisPlan.push(candidate.text);
  whyMetricGroups.push(candidate.metricKeys);
}

if (whyThisPlan.length < 2) {
  const fallback = [
    ['ctlActs', ctlNow, 'CTL'],
    ['atlActs', atlNow, 'ATL'],
    ['rampActs', rampNow, 'ramp rate'],
    ['totalTrimp', trimpNow, 'TRIMP'],
    ['restHR', restNow, 'resting HR'],
    ['hrvWel', hrvNow, 'HRV'],
    ['sleepWel', sleepNow, 'sleep score'],
    ['steps', stepsNow, 'steps'],
  ];
  for (const [key, value, label] of fallback) {
    if (whyThisPlan.length >= 2) break;
    if (value === null) continue;
    const alreadyUsed = whyMetricGroups.some((group) => group.includes(key));
    if (alreadyUsed) continue;
    whyThisPlan.push(`Señal clave: ${label} = ${fmt(value)}.`);
    whyMetricGroups.push([key]);
  }
}

if (whyThisPlan.length < 2) {
  whyThisPlan.push('Métricas insuficientes para justificar el plan con más detalle.');
  whyMetricGroups.push([]);
}

const whyThisPlanFinal = whyThisPlan.slice(0, 4);
const whyMetricGroupsFinal = whyMetricGroups.slice(0, 4);
const whyPlanMetricKeys = Array.from(new Set(whyMetricGroupsFinal.flat()));



const riskFlags = [];
if (hrvNow !== null && baselineHrv !== null && hrvNow < baselineHrv * 0.9) {
  riskFlags.push({
    trigger: 'wellnessLow',
    message: `HRV ${fmt(hrvNow)} vs base ${fmt(baselineHrv)} (>=10% por debajo).`,
    action: 'Prioriza recuperación y mantén intensidad baja en la próxima sesión.',
  });
}
if (restNow !== null && baselineRest !== null && restNow > baselineRest + 3) {
  riskFlags.push({
    trigger: 'restHrHigh',
    message: `FC reposo ${fmt(restNow)} bpm vs base ${fmt(baselineRest)} (+3 bpm).`,
    action: 'Reduce intensidad y monitoriza fatiga matinal durante 48h.',
  });
}
if (rampNow !== null && (rampNow > 5 || (baselineRamp !== null && rampNow > baselineRamp + 1.5))) {
  riskFlags.push({
    trigger: 'rampHigh',
    message: `Ramp alto (${fmt(rampNow)}).`,
    action: 'Evita añadir volumen extra esta semana.',
  });
}
if (sleepNow !== null && sleepNow < 70) {
  riskFlags.push({
    trigger: 'wellnessLow',
    message: `Sueño bajo (${fmt(sleepNow)}).`,
    action: 'Prioriza trabajo aeróbico suave hasta estabilizar el sueño.',
  });
}
if (ctlNow !== null && atlNow !== null && atlNow - ctlNow > 10) {
  riskFlags.push({
    trigger: 'atlOverload',
    message: `ATL (${fmt(atlNow)}) claramente por encima de CTL (${fmt(ctlNow)}).`,
    action: 'Añade recuperación entre esfuerzos de calidad.',
  });
}

const riskWarningTriggers = Array.from(new Set(riskFlags.map((flag) => flag.trigger)));
const riskWarningTriggerCounts = {
  wellnessLow: riskFlags.some((flag) => flag.trigger === 'wellnessLow') ? 1 : 0,
  rampHigh: riskFlags.some((flag) => flag.trigger === 'rampHigh') ? 1 : 0,
  painReported: riskFlags.some((flag) => flag.trigger === 'painReported') ? 1 : 0,
  restHrHigh: riskFlags.some((flag) => flag.trigger === 'restHrHigh') ? 1 : 0,
  atlOverload: riskFlags.some((flag) => flag.trigger === 'atlOverload') ? 1 : 0,
};
const riskWarningTriggerCount = riskWarningTriggers.length;

const hasWarningData = riskFlags.length > 0;
const warningLines = hasWarningData
  ? riskFlags.map((flag) => `${flag.message} Acción: ${flag.action}`)
  : ['Sin alertas relevantes con las señales actuales.'];

const sectionCompleteness = {
  lastWeekSummary: hasLastWeekSummaryData,
  thisWeekGoal: hasThisWeekGoalData,
  dailyPlan: hasCompleteDailyPlan,
  keySession: hasKeySessionData,
  warnings: hasWarningData,
};
const sectionMissingCount = Object.values(sectionCompleteness).filter((value) => !value).length;

const sections = [
  { title: 'Last-week summary', lines: lastWeekSummaryLines },
  { title: 'This-week goal', lines: thisWeekGoalLines },
  { title: 'Why this plan', lines: whyThisPlanFinal },
  { title: 'Daily plan', lines: dailyPlanLines },
  { title: 'Key session', lines: keySessionLines },
  { title: 'Warnings', lines: warningLines },
];

const keySessionSummary = hasKeySessionData ? keySessionLines[0] : 'Sin sesión clave.';
const warningSummary = hasWarningData ? warningLines[0] : 'Sin alertas relevantes.';
const keySessionDayLabel = keySessionDay ? valueOr(keySessionDay.day, 'la sesión clave') : 'la sesión clave';
const adjustmentRule = riskFlags.length > 0
  ? `Regla: si se repite la alerta, ${riskFlags[0].action}`
  : `Regla: si hoy notas fatiga alta, convierte ${keySessionDayLabel} en trabajo suave Z1-Z2 y prioriza recuperación.`;

const htmlParts = [];
htmlParts.push(`🏃‍♂️ <b>Plan semanal</b> ${esc(weekStart)} -> ${esc(weekEnd)}`);
if (zoneUpdateNotice) {
  htmlParts.push(esc(zoneUpdateNotice));
}
htmlParts.push('');
htmlParts.push('<b>TL;DR</b>');
htmlParts.push(`- Objetivo: ${esc(objective)}`);
htmlParts.push(`- Estado: Sueño ${esc(fmt(sleepNow))} · HRV ${esc(fmt(hrvNow))} · FC reposo ${esc(fmt(restNow, ' bpm'))}`);
htmlParts.push(`- Sesión clave: ${esc(keySessionSummary)}`);
htmlParts.push(`- Alerta: ${esc(warningSummary)}`);
htmlParts.push(`- ${esc(adjustmentRule)}`);
htmlParts.push('');

if (previewEnabled) {
  htmlParts.push('🧪 <b>Preview mode</b>');
  htmlParts.push(`- Mensajes enviados al chat preview ${esc(targetChatId)}.`);
  htmlParts.push('');
}

for (const section of sections) {
  htmlParts.push(`<b>${esc(section.title)}</b>`);
  for (const line of section.lines) {
    htmlParts.push(`- ${esc(line)}`);
  }
  htmlParts.push('');
}

const debugEnabled = isTruthy(getVar('RC_TELEGRAM_DEBUG_FOOTER'));

if (debugEnabled) {
  const runId = (content.runEvent && content.runEvent.runId)
    || content.runId
    || content.__runId
    || runContext.runId
    || '-';
  const attempt = content.__attempt ?? (content.runEvent && content.runEvent.attempt) ?? '-';
  const promptVersion = content.promptVersion || content.__promptVersion || runContext.promptVersion || '-';
  const modelId = content.modelId || content.__modelId || runContext.modelId || '-';
  htmlParts.push('<pre>'
    + `run_id: ${esc(runId)}\n`
    + `attempt: ${esc(attempt)}\n`
    + `prompt_version: ${esc(promptVersion)}\n`
    + `model: ${esc(modelId)}\n`
    + `template_version: ${esc(TEMPLATE_VERSION)}\n`
    + `sections_missing: ${esc(sectionMissingCount)}\n`
    + `preview_mode: ${esc(previewEnabled)}\n`
    + `chat_id: ${esc(targetChatId)}`
    + '</pre>');
}

const TELEGRAM_MESSAGE_BUDGET = 3900;
const htmlMessage = htmlParts.join('\n').trim();
const htmlMessageLength = Array.from(htmlMessage).length;
if (htmlMessageLength > TELEGRAM_MESSAGE_BUDGET) {
  throw new Error(`telegram_message_too_long: ${htmlMessageLength} > ${TELEGRAM_MESSAGE_BUDGET}`);
}

const errors = Array.isArray(content.__errors) ? content.__errors : [];
const baseRunEvent = isObject(content.runEvent)
  ? content.runEvent
  : {
      runId: `${new Date().toISOString()}-${Math.random().toString(36).slice(2, 8)}`,
      status: 'success',
      attempt: content.__attempt ?? null,
      weekStart: nextWeek.weekStart || null,
      weekEnd: nextWeek.weekEnd || null,
      errorCount: errors.length,
      errors,
      createdAt: new Date().toISOString(),
    };

const runEvent = Object.assign({}, baseRunEvent, {
  telegramTemplateVersion: TEMPLATE_VERSION,
  sectionCompleteness,
  sectionMissingCount,
  whyThisPlan: whyThisPlanFinal,
  whyPlanMetricKeys,
  whyPlanHallucinationFailures,
  previewMode: previewEnabled,
  previewChatId: targetChatId,
  riskWarningTriggerCount,
  riskWarningTriggers,
  riskWarningTriggerCounts,
  telegramMessageBudget: TELEGRAM_MESSAGE_BUDGET,
  telegramMessageLength: htmlMessageLength,
});

return [{
  json: Object.assign({}, content, runEvent, {
    runEvent,
    telegramTemplateVersion: TEMPLATE_VERSION,
    sectionCompleteness,
    sectionMissingCount,
    whyThisPlan: whyThisPlanFinal,
    whyPlanMetricKeys,
    whyPlanHallucinationFailures,
    previewMode: previewEnabled,
    previewChatId: targetChatId,
    riskWarningTriggerCount,
    riskWarningTriggers,
    riskWarningTriggerCounts,
    telegramMessageBudget: TELEGRAM_MESSAGE_BUDGET,
    telegramMessageLength: htmlMessageLength,
    chatId: targetChatId,
    htmlMessage,
  }),
}];
